async function stats() {
  const [projects, tasks] = await Promise.all([
    apiGet('/api/projects?limit=100'),
    apiGet('/api/tasks?limit=100'),
  ]);

  // Fetch all pages if needed
  const allProjects = [...projects.data];
  let page = 2;
  while (allProjects.length < projects.total) {
    const more = await apiGet(`/api/projects?page=${page}&limit=100`);
    allProjects.push(...more.data);
    page++;
  }

  const allTasks = [...tasks.data];
  page = 2;
  while (allTasks.length < tasks.total) {
    const more = await apiGet(`/api/tasks?page=${page}&limit=100`);
    allTasks.push(...more.data);
    page++;
  }

  const byStatus = {};
  const byPriority = {};
  for (const t of allTasks) {
    byStatus[t.status] = (byStatus[t.status] || 0) + 1;
    byPriority[t.priority] = (byPriority[t.priority] || 0) + 1;
  }

  console.log('\nTaskFlow Statistics\n');
  console.log(`  Total projects: ${allProjects.length}`);
  console.log(`  Total tasks:    ${allTasks.length}`);
  console.log();

  console.log('  Tasks by status:');
  for (const s of ['todo', 'in_progress', 'review', 'done', 'cancelled']) {
    if (byStatus[s]) console.log(`    ${s.padEnd(14)} ${byStatus[s]}`);
  }
  console.log();

  console.log('  Tasks by priority:');
  for (const p of ['urgent', 'high', 'medium', 'low']) {
    if (byPriority[p]) console.log(`    ${p.padEnd(14)} ${byPriority[p]}`);
  }
  console.log();
}

async function exportProject(flags) {
  if (!flags.project) {
    console.error('Error: --project <id> is required');
    process.exitCode = 1;
    return;
  }

  const format = flags.format || 'json';
  if (format !== 'json' && format !== 'csv') {
    console.error('Error: --format must be "json" or "csv"');
    process.exitCode = 1;
    return;
  }

  const project = await apiGet(`/api/projects/${flags.project}`);

  const params = new URLSearchParams({ projectId: flags.project, limit: '100' });
  let page = 1;
  const allTasks = [];
  while (true) {
    params.set('page', String(page));
    const result = await apiGet(`/api/tasks?${params}`);
    allTasks.push(...result.data);
    if (allTasks.length >= result.total) break;
    page++;
  }

  if (format === 'json') {
    const output = {
      exportedAt: new Date().toISOString(),
      format: 'json',
      project: {
        id: project.id,
        name: project.name,
        status: project.status,
        members: project.members,
        taskCount: allTasks.length,
        completedCount: allTasks.filter(t => t.status === 'done').length,
      },
      tasks: allTasks,
    };
    console.log(JSON.stringify(output, null, 2));
  } else {
    // CSV
    const headers = ['id', 'title', 'status', 'priority', 'assigneeId', 'tags', 'createdAt', 'updatedAt'];
    const csvEscape = (val) => {
      const str = String(val);
      if (str.includes(',') || str.includes('"') || str.includes('\n')) {
        return '"' + str.replace(/"/g, '""') + '"';
      }
      return str;
    };
    console.log(headers.join(','));
    for (const t of allTasks) {
      const row = headers.map(h => {
        const val = t[h];
        if (Array.isArray(val)) return csvEscape(val.join('; '));
        return csvEscape(val == null ? '' : val);
      });
      console.log(row.join(','));
    }
  }
}

function printUsage() {
  console.log(`
TaskFlow CLI - Admin tool for the TaskFlow API

Usage: node src/cli.js <command> [options]

Commands:
  list-projects                         List all projects
  list-tasks --project <id> [--status]  List tasks for a project
  create-project --name <n> --owner <id>
                                        Create a new project
  create-task --title <t> --project <id> [--priority <p>] [--assignee <id>]
                                        Create a new task
  update-task <id> --status <s>         Update a task's status
  stats                                 Show aggregate statistics
  export --project <id> [--format json|csv]
                                        Export project data

Environment:
  TASKFLOW_URL  API base URL (default: http://localhost:3000)
`);
}

// --- Main ---

async function main() {
  const { command, positional, flags } = parseArgs(process.argv);

  try {
    switch (command) {
      case 'list-projects':
        await listProjects();
        break;
      case 'list-tasks':
        await listTasks(flags);
        break;
      case 'create-project':
        await createProject(flags);
        break;
      case 'create-task':
        await createTask(flags);
        break;
      case 'update-task':
        await updateTask(positional, flags);
        break;
      case 'stats':
        await stats();
        break;
      case 'export':
        await exportProject(flags);
        break;
      case 'help':
      case '--help':
      case '-h':
        printUsage();
        break;
      default:
        if (command) {
          console.error(`Error: Unknown command "${command}"`);
        }
        printUsage();
        process.exitCode = 1;
        break;
    }
  } catch (err) {
    console.error(`\nError: ${err.message}`);
    process.exitCode = 1;
  }
}

