    }
  }

  return { command, positional, flags };
}

// --- HTTP helpers ---

async function apiGet(path) {
  const res = await fetch(`${BASE_URL}${path}`);
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(body.error || `HTTP ${res.status}`);
  }
  return res.json();
}

async function apiPost(path, data) {
  const res = await fetch(`${BASE_URL}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data),
  });
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(body.error || `HTTP ${res.status}`);
  }
  return res.json();
}

async function apiPatch(path, data) {
  const res = await fetch(`${BASE_URL}${path}`, {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data),
  });
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(body.error || `HTTP ${res.status}`);
  }
  return res.json();
}

// --- Table formatting ---

function formatTable(rows, columns) {
  if (rows.length === 0) {
    return '  (no results)';
  }

  const widths = columns.map(col =>
    Math.max(col.header.length, ...rows.map(r => String(col.value(r)).length))
  );

  const header = columns.map((col, i) => col.header.padEnd(widths[i])).join('  ');
  const separator = widths.map(w => '-'.repeat(w)).join('  ');
  const body = rows.map(row =>
    columns.map((col, i) => String(col.value(row)).padEnd(widths[i])).join('  ')
  );

  return [header, separator, ...body].join('\n');
}

// --- Commands ---

async function listProjects() {
  let page = 1;
  const allProjects = [];
  while (true) {
    const result = await apiGet(`/api/projects?page=${page}&limit=100`);
    allProjects.push(...result.data);
    if (allProjects.length >= result.total) break;
    page++;
  }

  console.log(`\nProjects (${allProjects.length} total)\n`);
  console.log(formatTable(allProjects, [
    { header: 'ID', value: r => r.id },
    { header: 'Name', value: r => r.name },
    { header: 'Status', value: r => r.status },
    { header: 'Owner', value: r => r.ownerId },
    { header: 'Members', value: r => r.members.length },
    { header: 'Created', value: r => r.createdAt.slice(0, 10) },
  ]));
  console.log();
}

async function listTasks(flags) {
  if (!flags.project) {
    console.error('Error: --project <id> is required');
    process.exitCode = 1;
    return;
  }

  const params = new URLSearchParams({ projectId: flags.project, limit: '100' });
  if (flags.status) params.set('status', flags.status);

  let page = 1;
  const allTasks = [];
  while (true) {
    params.set('page', String(page));
    const result = await apiGet(`/api/tasks?${params}`);
    allTasks.push(...result.data);
    if (allTasks.length >= result.total) break;
    page++;
  }

  const label = flags.status ? ` [status=${flags.status}]` : '';
  console.log(`\nTasks for ${flags.project}${label} (${allTasks.length} total)\n`);
  console.log(formatTable(allTasks, [
    { header: 'ID', value: r => r.id },
    { header: 'Title', value: r => r.title },
    { header: 'Status', value: r => r.status },
    { header: 'Priority', value: r => r.priority },
    { header: 'Assignee', value: r => r.assigneeId || '-' },
    { header: 'Tags', value: r => r.tags.length > 0 ? r.tags.join(', ') : '-' },
  ]));
  console.log();
}

async function createProject(flags) {
  if (!flags.name) {
    console.error('Error: --name <name> is required');
    process.exitCode = 1;
    return;
  }
  if (!flags.owner) {
    console.error('Error: --owner <userId> is required');
    process.exitCode = 1;
    return;
  }

  const project = await apiPost('/api/projects', {
    name: flags.name,
    ownerId: flags.owner,
  });
  console.log(`\nCreated project: ${project.id}`);
  console.log(`  Name:    ${project.name}`);
  console.log(`  Owner:   ${project.ownerId}`);
  console.log(`  Status:  ${project.status}`);
  console.log();
}

async function createTask(flags) {
  if (!flags.title) {
    console.error('Error: --title <title> is required');
    process.exitCode = 1;
    return;
  }
  if (!flags.project) {
    console.error('Error: --project <projectId> is required');
    process.exitCode = 1;
    return;
  }

  const body = {
    title: flags.title,
    projectId: flags.project,
  };
  if (flags.priority) body.priority = flags.priority;
  if (flags.assignee) body.assigneeId = flags.assignee;

  const task = await apiPost('/api/tasks', body);
  console.log(`\nCreated task: ${task.id}`);
  console.log(`  Title:    ${task.title}`);
  console.log(`  Project:  ${task.projectId}`);
  console.log(`  Status:   ${task.status}`);
  console.log(`  Priority: ${task.priority}`);
  if (task.assigneeId) console.log(`  Assignee: ${task.assigneeId}`);
  console.log();
}

async function updateTask(positional, flags) {
  const taskId = positional[0];
  if (!taskId) {
    console.error('Error: task ID is required (e.g., update-task task_1 --status done)');
    process.exitCode = 1;
    return;
  }
  if (!flags.status) {
    console.error('Error: --status <status> is required');
    process.exitCode = 1;
    return;
  }

  const task = await apiPatch(`/api/tasks/${taskId}`, { status: flags.status });
  console.log(`\nUpdated task: ${task.id}`);
  console.log(`  Title:    ${task.title}`);
  console.log(`  Status:   ${task.status}`);
  console.log(`  Priority: ${task.priority}`);
  console.log();
}

async function stats() {
  const [projects, tasks] = await Promise.all([
    apiGet('/api/projects?limit=100'),
    apiGet('/api/tasks?limit=100'),
  ]);

  // Fetch all pages if needed
  const allProjects = [...projects.data];
  let page = 2;
  while (allProjects.length < projects.total) {
    const more = await apiGet(`/api/projects?page=${page}&limit=100`);
    allProjects.push(...more.data);
    page++;
  }

  const allTasks = [...tasks.data];
  page = 2;
  while (allTasks.length < tasks.total) {
    const more = await apiGet(`/api/tasks?page=${page}&limit=100`);
    allTasks.push(...more.data);
    page++;
  }

  const byStatus = {};
  const byPriority = {};
  for (const t of allTasks) {
    byStatus[t.status] = (byStatus[t.status] || 0) + 1;
    byPriority[t.priority] = (byPriority[t.priority] || 0) + 1;
  }

  console.log('\nTaskFlow Statistics\n');
  console.log(`  Total projects: ${allProjects.length}`);
  console.log(`  Total tasks:    ${allTasks.length}`);
  console.log();

  console.log('  Tasks by status:');
  for (const s of ['todo', 'in_progress', 'review', 'done', 'cancelled']) {
    if (byStatus[s]) console.log(`    ${s.padEnd(14)} ${byStatus[s]}`);
  }
  console.log();

  console.log('  Tasks by priority:');
  for (const p of ['urgent', 'high', 'medium', 'low']) {
    if (byPriority[p]) console.log(`    ${p.padEnd(14)} ${byPriority[p]}`);
  }
  console.log();
}

async function exportProject(flags) {
  if (!flags.project) {
    console.error('Error: --project <id> is required');
    process.exitCode = 1;
    return;
  }

  const format = flags.format || 'json';
  if (format !== 'json' && format !== 'csv') {
    console.error('Error: --format must be "json" or "csv"');
    process.exitCode = 1;
    return;
  }

  const project = await apiGet(`/api/projects/${flags.project}`);

  const params = new URLSearchParams({ projectId: flags.project, limit: '100' });
  let page = 1;
  const allTasks = [];
  while (true) {
    params.set('page', String(page));
    const result = await apiGet(`/api/tasks?${params}`);
    allTasks.push(...result.data);
    if (allTasks.length >= result.total) break;
    page++;
  }

  if (format === 'json') {
    const output = {
      exportedAt: new Date().toISOString(),
      format: 'json',
      project: {
        id: project.id,
        name: project.name,
        status: project.status,
        members: project.members,
        taskCount: allTasks.length,
        completedCount: allTasks.filter(t => t.status === 'done').length,
      },
      tasks: allTasks,
    };
    console.log(JSON.stringify(output, null, 2));
  } else {
    // CSV
    const headers = ['id', 'title', 'status', 'priority', 'assigneeId', 'tags', 'createdAt', 'updatedAt'];
    const csvEscape = (val) => {
      const str = String(val);
      if (str.includes(',') || str.includes('"') || str.includes('\n')) {
        return '"' + str.replace(/"/g, '""') + '"';
      }
      return str;
    };
    console.log(headers.join(','));
    for (const t of allTasks) {
      const row = headers.map(h => {
        const val = t[h];
        if (Array.isArray(val)) return csvEscape(val.join('; '));
        return csvEscape(val == null ? '' : val);
      });
      console.log(row.join(','));
    }
  }
}

function printUsage() {
  console.log(`
TaskFlow CLI - Admin tool for the TaskFlow API

Usage: node src/cli.js <command> [options]

Commands:
  list-projects                         List all projects
  list-tasks --project <id> [--status]  List tasks for a project
  create-project --name <n> --owner <id>
                                        Create a new project
  create-task --title <t> --project <id> [--priority <p>] [--assignee <id>]
                                        Create a new task
  update-task <id> --status <s>         Update a task's status
  stats                                 Show aggregate statistics
  export --project <id> [--format json|csv]
                                        Export project data

Environment:
  TASKFLOW_URL  API base URL (default: http://localhost:3000)
`);
}

// --- Main ---

async function main() {
  const { command, positional, flags } = parseArgs(process.argv);

  try {
    switch (command) {
      case 'list-projects':
        await listProjects();
        break;
      case 'list-tasks':
        await listTasks(flags);
        break;
      case 'create-project':
        await createProject(flags);
        break;
      case 'create-task':
        await createTask(flags);
        break;
      case 'update-task':
        await updateTask(positional, flags);
        break;
      case 'stats':
        await stats();
        break;
      case 'export':
        await exportProject(flags);
        break;
      case 'help':
      case '--help':
      case '-h':
        printUsage();
        break;
      default:
        if (command) {
          console.error(`Error: Unknown command "${command}"`);
        }
        printUsage();
        process.exitCode = 1;
        break;
    }
  } catch (err) {
    console.error(`\nError: ${err.message}`);
    process.exitCode = 1;
  }
}

export {
  parseArgs,
  formatTable,
  listProjects,
  listTasks,
  createProject,
  createTask,
  updateTask,
  stats,
  exportProject,
  main,
  BASE_URL,
};

main();
"}}

