async function main() {
  const { command, positional, flags } = parseArgs(process.argv);

  try {
    switch (command) {
      case 'list-projects':
        await listProjects();
        break;
      case 'list-tasks':
        await listTasks(flags);
        break;
      case 'create-project':
        await createProject(flags);
        break;
      case 'create-task':
        await createTask(flags);
