async function run(argv) {
  const { command, positional, flags } = parseArgs(argv);

  switch (command) {
    case 'list-projects':
      await listProjects();
      break;
    case 'list-tasks':
      await listTasks(flags);
      break;
    case 'create-project':
      await createProject(flags);
