      await stats();
      break;
    case 'export':
      await exportProject(flags);
      break;
    case 'help':
    case '--help':
    case '-h':
      printUsage();
      break;
    default:
      if (command) {
        console.error(`Error: Unknown command "${command}"`);
      }
      printUsage();
      process.exitCode = 1;
      break;
  }
}

