async function listTasks(flags) {
  if (!flags.project) {
    console.error('Error: --project <id> is required');
    process.exitCode = 1;
    return;
  }

  const params = new URLSearchParams({ projectId: flags.project, limit: '100' });
  if (flags.status) params.set('status', flags.status);

  let page = 1;
  const allTasks = [];
  while (true) {
    params.set('page', String(page));
    const result = await apiGet(`/api/tasks?${params}`);
    allTasks.push(...result.data);
    if (allTasks.length >= result.total) break;
    page++;
  }

  const label = flags.status ? ` [status=${flags.status}]` : '';
  console.log(`\nTasks for ${flags.project}${label} (${allTasks.length} total)\n`);
  console.log(formatTable(allTasks, [
    { header: 'ID', value: r => r.id },
    { header: 'Title', value: r => r.title },
    { header: 'Status', value: r => r.status },
    { header: 'Priority', value: r => r.priority },
    { header: 'Assignee', value: r => r.assigneeId || '-' },
    { header: 'Tags', value: r => r.tags.length > 0 ? r.tags.join(', ') : '-' },
  ]));
  console.log();
}

