async function stats() {
  const [projects, tasks] = await Promise.all([
    apiGet('/api/projects?limit=100'),
    apiGet('/api/tasks?limit=100'),
  ]);

  // Fetch all pages if needed
  const allProjects = [...projects.data];
  let page = 2;
  while (allProjects.length < projects.total) {
    const more = await apiGet(`/api/projects?page=${page}&limit=100`);
    allProjects.push(...more.data);
    page++;
  }

  const allTasks = [...tasks.data];
  page = 2;
  while (allTasks.length < tasks.total) {
    const more = await apiGet(`/api/tasks?page=${page}&limit=100`);
    allTasks.push(...more.data);
    page++;
  }

  const byStatus = {};
  const byPriority = {};
  for (const t of allTasks) {
    byStatus[t.status] = (byStatus[t.status] || 0) + 1;
    byPriority[t.priority] = (byPriority[t.priority] || 0) + 1;
  }

  console.log('\nTaskFlow Statistics\n');
  console.log(`  Total projects: ${allProjects.length}`);
  console.log(`  Total tasks:    ${allTasks.length}`);
  console.log();

  console.log('  Tasks by status:');
  for (const s of ['todo', 'in_progress', 'review', 'done', 'cancelled']) {
    if (byStatus[s]) console.log(`    ${s.padEnd(14)} ${byStatus[s]}`);
  }
  console.log();

  console.log('  Tasks by priority:');
  for (const p of ['urgent', 'high', 'medium', 'low']) {
    if (byPriority[p]) console.log(`    ${p.padEnd(14)} ${byPriority[p]}`);
  }
  console.log();
}

